/* wif-wcs-locationmaster-interface-sql-oracle.xml - insertLocationMaster - 로케이션마스터 등록 SQL */
INSERT INTO TWIF_WCS_LOCMST_SYNC
(
	WCSSEQ
	, IFCD
	, CTKEY
	, OWKEY
	, TOTLOCDELYN
	, LCKEY
	, ARKEY
	, ICKEY
	, ICBRCD
	, PAKBRCD
	, CTNBRCD
	, ICNM
	, DELYN
	, WIFIFID
	, IFID
	, IFREQDT
	, IFTYPE
	, IFSRCMODULE
	, IFTGTMODULE
	, IFSTATUS
	, IFERRCD
	, IFERRMSG
	, IFPRCSDATE
	, ORD
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
	,IFRETRYYN
	,IFRETRYIFID
)
VALUES(
	#{wcsSeq}
	,#{ifCd}
	,#{ctKey}
	,#{owKey}
	,#{totLocDelYn}
	,#{lcKey}
	,#{arKey}
	,#{icKey}
	,#{icBrcd}
	,#{pakBrcd}
	,#{ctnBrcd}
	,#{icNm}
	,#{delYn}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{ifretryyn}
	,#{ifretryifid}
)

mapper.update:
/* wif-wcs-locationmaster-interface-sql-oracle.xml - updateInterfaceStatusWcsResult - WCS Interface Result UPDATE SQL */
UPDATE ${tableName}
   SET IFSTATUS		= #{ifStatus}
	   ,IFERRCD		= #{ifErrCd}
	   ,IFERRMSG	= #{ifErrMsg}
	   ,IFPRCSDATE	= #{sysdate}
	   ,UPDATEDATE  = #{sysdate}
	   ,UPDATEURKEY = #{surkey}
 WHERE WCSSEQ 		= #{wcsSeq}
